  ('elementary-0489de64-moex-00231', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '捷運路線跨越不相隸屬之行政區域者，由各有關縣（市）政府協議決定地方主管機關，若協議不成者，則 由下列何者指定之？', '["鐵道局", "交通部", "行政院", "總統府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
