  ('elementary-0489de64-moex-00233', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '自然人使用之遙控無人機，其最大起飛重量達多少克以上，應由其所有人檢附文件向交通部民用航空局申 請註冊，並於註冊完成後，將始得操作？', '["100克以上", "150克以上", "200克以上", "250克以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
